// Compile daily briefing data
const bookings = $('Get Today\'s Bookings').all();
const pendingGuestLists = $('Check Guest List Status').all();
const facilityStatus = $('Check Facility Prep Status').first().json;

const now = new Date();
const dayOfWeek = now.toLocaleDateString('en-US', { weekday: 'long' });
const formattedDate = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Process bookings
const bookingsList = bookings.map(b => {
  const booking = b.json;
  const startTime = new Date(booking.startDateTime);
  const endTime = new Date(booking.endDateTime);
  return {
    bookingId: booking.bookingId,
    memberName: booking.memberName,
    spaceType: booking.spaceType,
    startTime: startTime.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true }),
    endTime: endTime.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true }),
    expectedGuests: booking.expectedGuests || 0,
    eventType: booking.eventType,
    guestListSubmitted: booking.guestListSubmitted || false,
    specialRequirements: booking.specialRequirements || 'None'
  };
}).sort((a, b) => a.startTime.localeCompare(b.startTime));

// Count stats
const totalBookings = bookingsList.length;
const totalGuests = bookingsList.reduce((sum, b) => sum + b.expectedGuests, 0);
const pendingGuestListsCount = pendingGuestLists.length;

// Generate concierge checklist
const conciergeChecklist = [
  { task: 'Review all bookings for the day', priority: 'high', completed: false },
  { task: 'Verify guest lists are submitted', priority: 'high', completed: pendingGuestListsCount === 0 },
  { task: 'Check facility prep status', priority: 'high', completed: facilityStatus.prepComplete || false },
  { task: 'Confirm equipment reservations', priority: 'medium', completed: false },
  { task: 'Review special requirements for each booking', priority: 'medium', completed: false },
  { task: 'Prepare welcome materials for new members', priority: 'low', completed: false },
  { task: 'Check inventory levels', priority: 'low', completed: false },
  { task: 'Review member feedback from yesterday', priority: 'low', completed: false }
];

// Add booking-specific tasks
bookingsList.forEach(booking => {
  if (booking.specialRequirements !== 'None') {
    conciergeChecklist.push({
      task: `Prepare special requirements for ${booking.memberName}: ${booking.specialRequirements}`,
      priority: 'high',
      completed: false
    });
  }
});

return {
  date: formattedDate,
  dayOfWeek,
  summary: {
    totalBookings,
    totalExpectedGuests: totalGuests,
    pendingGuestLists: pendingGuestListsCount,
    facilityReady: facilityStatus.prepComplete || false
  },
  bookings: bookingsList,
  pendingGuestLists: pendingGuestLists.map(p => p.json),
  facilityStatus,
  conciergeChecklist,
  alerts: generateAlerts(pendingGuestListsCount, facilityStatus, bookingsList)
};

function generateAlerts(pendingLists, facility, bookings) {
  const alerts = [];

  if (pendingLists > 0) {
    alerts.push({
      type: 'warning',
      message: `${pendingLists} booking(s) missing guest list submission`,
      action: 'Contact members to submit guest lists'
    });
  }

  if (!facility.prepComplete) {
    alerts.push({
      type: 'warning',
      message: 'Facility prep not marked as complete',
      action: 'Verify cleaning and setup is done'
    });
  }

  if (facility.maintenanceIssues && facility.maintenanceIssues.length > 0) {
    alerts.push({
      type: 'critical',
      message: `${facility.maintenanceIssues.length} maintenance issue(s) reported`,
      action: 'Review and address before first booking'
    });
  }

  const largeEvents = bookings.filter(b => b.expectedGuests > 20);
  if (largeEvents.length > 0) {
    alerts.push({
      type: 'info',
      message: `${largeEvents.length} large event(s) today (20+ guests)`,
      action: 'Ensure adequate staffing and supplies'
    });
  }

  return alerts;
}

// Get members with pending guest lists and send reminders
const briefing = $input.first().json;
const pendingBookings = briefing.pendingGuestLists;

return pendingBookings.map(booking => ({
  bookingId: booking.bookingId,
  memberName: booking.memberName,
  memberEmail: booking.memberEmail,
  memberPhone: booking.memberPhone,
  spaceType: booking.spaceType,
  startTime: new Date(booking.startDateTime).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true }),
  isUrgent: true
}));

// Compile end-of-day summary
const data = $input.first().json;
const bookings = data.bookings || data;
const now = new Date();

const completed = Array.isArray(bookings) ? bookings.filter(b => b.status === 'completed') : [];
const cancelled = Array.isArray(bookings) ? bookings.filter(b => b.status === 'cancelled') : [];
const noShows = Array.isArray(bookings) ? bookings.filter(b => b.status === 'no_show') : [];

const totalRevenue = completed.reduce((sum, b) => sum + (b.revenue || 0), 0);
const totalHoursUsed = completed.reduce((sum, b) => sum + (b.durationHours || 0), 0);
const totalGuests = completed.reduce((sum, b) => sum + (b.actualGuests || b.expectedGuests || 0), 0);

return {
  date: now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
  stats: {
    totalBookings: Array.isArray(bookings) ? bookings.length : 0,
    completedBookings: completed.length,
    cancelledBookings: cancelled.length,
    noShows: noShows.length,
    totalRevenue,
    totalHoursUsed,
    totalGuests,
    averageRating: data.averageRating || 0
  },
  highlights: data.highlights || [],
  issues: data.issues || [],
  tomorrowBookings: data.tomorrowCount || 0
};
